var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…버려진 함선 치고 내부는 생각보다 깨끗하네.","JPN":"……捨てられた艦船にしては、中はずいぶん綺麗じゃん。","ENG":"…Not bad for an abandoned ship. It's cleaner than I expected.","TWN":"…雖然是廢棄的艦船，但內部比想像中乾淨。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"도깨비 같은 게 튀어나오는 건 아니겠지?","JPN":"お化けとか出てきたりしないよね？","ENG":"Hope nothing ghostly like a demon jumps out at us.","TWN":"不會有鬼怪跳出來吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"신호는 안쪽에서 잡히고 있어.","JPN":"信号は中のほうから出ている。","ENG":"The signal's coming from deeper inside.","TWN":"訊號在裡面。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L6_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…같이 가!","JPN":"……待って！","ENG":"…Wait up!","TWN":"…一起走！"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"데이터 뱅크 찾았어. 생각보다 찾기 쉬운데? 암호화도 안되어 있고.","JPN":"データバンク、あったよ。思ったより簡単だったね。暗号化もされてないし。","ENG":"Found the data bank. That was easier than I thought. It's not even encrypted.","TWN":"找到資料庫了。比想像中好找？也沒有加密。"},"stage":{"bg":"PROLOGUE_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L11_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그럼 임무 완수군. 가지고 돌아가면 될 거다.","JPN":"じゃあ任務完了だな。それを持ち帰ればいいはずだ。","ENG":"Then mission accomplished. Let's bring it back.","TWN":"那任務就完成了。帶回去就行。"},"stage":{"bg":"PROLOGUE_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふーん……","ENG":"Hmm…","TWN":"嗯…"},"stage":{"bg":"PROLOGUE_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L13_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"뭘 관측하는 장치인가 했더니, 침식파 탐지 기록이 담겨있었구나.","JPN":"何を観測する装置かと思ったら、侵食波探知記録が保存されてる。","ENG":"Thought it was some kind of observatory device, but it's full of Corruption ray scan logs.","TWN":"我還以為是什麼觀測裝置，結果裡面裝的是侵蝕波探測紀錄。"},"stage":{"bg":"PROLOGUE_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L14_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"의뢰인이 부탁한 걸 왜 멋대로 읽고 있지?","JPN":"依頼人に頼まれたものを、なぜ勝手に読んでいる？","ENG":"Why are you reading it? That wasn't part of the job.","TWN":"為什麼擅自讀委託人的東西？"},"stage":{"bg":"PROLOGUE_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"왜? 의뢰에 기록을 읽으면 안된다는 조항이라도 있었어?","JPN":"何？　依頼に、記録を読んじゃだめという条項があったの？","ENG":"Why not? Was there a clause saying we're not allowed to read the records during a job?","TWN":"怎麼？委託有規定不能讀取紀錄嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…아니.","JPN":"……いや。","ENG":"…No.","TWN":"…沒有。"},"stage":{"bg":"PROLOGUE_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"뭐라고 쓰여있는데?","JPN":"何と書かれている？","ENG":"So, what does it say?","TWN":"上面寫了什麼？"},"stage":{"bg":"PROLOGUE_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"여기서 뭔가를 추적하고 있었나 봐. 우물이라 명명된 특정 좌표에서… 엄청 오랫동안.","JPN":"ここで何かを追跡してたみたい。「井戸」と命名された特定の座標で……すごく長い間。","ENG":"Looks like they were tracking something. In fixed coordinates marked as the Well… for a very long time.","TWN":"他們好像在這裡追蹤什麼。在一個被命名為井的特定座標…追蹤了很久。"},"stage":{"bg":"PROLOGUE_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L20_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"근데 추적하고 있던 게 평범한 침식체는 아닌 것 같아.","JPN":"でも、追跡していたのは普通の侵食体じゃないみたい。","ENG":"And whatever they were tracking wasn't an ordinary C.O.","TWN":"但追蹤的好像不是普通的侵蝕體。"},"stage":{"bg":"PROLOGUE_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이상침식파 시그니처 감지… 식별 타입은…","JPN":"異常侵食波シグネチャー感知……識別タイプは……","ENG":"Abnormal Corruption ray signature detected… classification type…","TWN":"偵測到異常侵蝕波訊號…識別類型是…"},"stage":{"bg":"MAINSTREAM_000002","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"심연 원종… 세 짐승의 범?","JPN":"深淵原種……3匹のケモノの、虎？","ENG":"Primal Abyssal… Tiger of the Three Beasts?","TWN":"深淵原種…三隻野獸的虎？"},"stage":{"bg":"MAINSTREAM_000002","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"위험한 녀석인가?","JPN":"危険なやつなのか？","ENG":"Is it dangerous?","TWN":"是個危險的傢伙嗎？"},"stage":{"bg":"MAINSTREAM_000002","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"나도 모르겠어. 오피셜 리스트에도 없고.","JPN":"私にも分からない。オフィシャルリストに載ってないし。","ENG":"Beats me. Doesn't show up on any official lists.","TWN":"我也不知道。官方名單上沒有。"},"stage":{"bg":"MAINSTREAM_000002","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"관리국이 공개한 적 없는 이레귤러라면… 제법 위험한 녀석일지도?","JPN":"管理局が公開してないイレギュラーってことは……結構ヤバいやつかも？","ENG":"If it's an Irregular the Administration never disclosed… It could be real bad.","TWN":"如果這是管理局從未公開過的異類…那可能很危險。"},"stage":{"bg":"MAINSTREAM_000002","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이 함교의 데이터베이스를 뒤져보면 이 시그니처에 대한 정보를 얻을 수 있지 않을까?","JPN":"この艦橋のデータベースを漁ってみたら、このシグネチャーに関する情報が手に入るんじゃないかな？","ENG":"Maybe we'll find more on the signature if we dig into the bridge's database.","TWN":"如果查一下這艘艦橋的資料庫，是不是就能得到關於這個訊號的情報？"},"stage":{"bg":"MAINSTREAM_000002","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L30_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"거기까지만 하지. 이런 일에 너무 깊이 관여하면 좋은 꼴을 못 볼…","JPN":"そこまでにしろ。こんなことに深入りすると、いい目を見な……","ENG":"Let's stop here. Get too deep in this kind of thing and it never ends well–","TWN":"到此為止吧。過度涉入這種事，不會有好下場的…"},"stage":{"bg":"MAINSTREAM_000002","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"너, 내 말을 듣고 있긴 한 거냐?","JPN":"お前、話聞いているのか？","ENG":"Hey, are you even listening to me?","TWN":"你到底有沒有在聽我說話？"},"stage":{"bg":"MAINSTREAM_000003","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"관리국 데이터에 접근해볼 기회가 자주 있는 일은 아니잖아.","JPN":"管理局のデータベースにアクセスできる機会なんてめったにないんだよ。","ENG":"Come on, chances to access Administration data don't come every day.","TWN":"不是經常有機會能進入管理局的資料庫的。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"어르신은 궁금한 거 없어?","JPN":"おばあさんは知りたいこととかないの？","ENG":"Aren't you curious at all, granny?","TWN":"阿姨你沒有什麼好奇的嗎？"},"stage":{"bg":"MAINSTREAM_000003","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"혹시 내 이름에 관한…","JPN":"もしかして私の名前に関する……","ENG":"Is there anything about my name…?","TWN":"比如說我的名字…"},"stage":{"bg":"MAINSTREAM_000003","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이름?","JPN":"名前？","ENG":"You name?","TWN":"名字？"},"stage":{"bg":"MAINSTREAM_000003","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"MAINSTREAM_000003","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"아니, 관두지.","JPN":"いや、やめておく。","ENG":"Forget it.","TWN":"算了，別提了。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"으음… 관리국 기밀 자료 같은 건 안 보이네. 전부 폐기된 건지, 현장 데이터 몇 개만 남아있어.","JPN":"うーん……管理局の機密資料のようなものは見当たらないね。全部破棄されたのか、現場のデータがいくつか残ってるだけ。","ENG":"Hmm… Nothing classified from the Administration. Just a few data logs left. Everything else must've been wiped.","TWN":"嗯…沒有看到管理局的機密資料。可能都銷毀了，只剩下幾個現場資料。"},"stage":{"bg":"PROLOGUE_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"앗, 통신 기록 발견!","JPN":"あっ、通信記録発見！","ENG":"Ah, I found some comms records!","TWN":"啊，發現通訊紀錄！"},"stage":{"bg":"PROLOGUE_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L43_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"어디- 관리국 사람들은 무슨 농담을 나눴는지 확인해볼까?","JPN":"どれどれ～管理局の人はどんな冗談を言い合うのかな？","ENG":"Let's see… what kind of jokes the Administration agents cracked on the job.","TWN":"來—看看管理局的人聊了什麼笑話？"},"stage":{"bg":"PROLOGUE_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"우물 아래에서 보내는 이 메시지가 닿을진 모르겠지만… 당신에게 꼭 하고 싶은 말이 있어.","JPN":"イドの下から送るメッセージがあなたに届くかは分からないけど……あなたに伝えたいことがあるの。","ENG":"I don't know if this message will reach you from down in the Well… But there's something I need to tell you.","TWN":"這條來自井底的訊息，我不知道你能不能收到…但我有一句話一定要告訴你。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L46_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"오, 예쁜 여자 목소리네. 사랑의 메시지 같은 건가?","JPN":"お、綺麗な女の人の声だ。恋のメッセージか何かかな？","ENG":"Whoa. Pretty voice from a woman. Is this a love message or something?","TWN":"喔，是個好聽的女人聲音。是情書嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"만약 내가 당신을 잃게 된다면 말이야.","JPN":"もし私があなたを失ってしまったら。","ENG":"If I ever lose you…","TWN":"如果，我失去了你。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"난 평생을 회한에 잠긴 채로 남은 여생을 살아갈 거야.","JPN":"私は後悔に満ちたまま、残りの人生を生きるわ。","ENG":"I'll spend the rest of my life drowning in regret.","TWN":"我會一輩子活在悔恨之中。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"당신도, 나도 그런 미래를 바란 적은 없겠지만… 인생이란 건 원래 뜻대로 안 되는 거잖아.","JPN":"あなたも私も、そんな未来は望んでないけど……人生って思い通りにいかないものでしょう。","ENG":"Neither of us wanted that future… but life doesn't care what we want, does it?","TWN":"你和我都不想要那樣的未來，但人生本來就不會事事如意。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L2_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니 이것 하나만 약속해줘.","JPN":"だからこれだけは約束してちょうだい。","ENG":"So just promise me this.","TWN":"所以請你答應我一件事。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"언젠가, 우리 둘 중 한 사람만 남게 된다면…","JPN":"いつか、あなたと私のどちらかが一人残されることになったら……","ENG":"If either of us ends up alone…","TWN":"總有一天，如果我們兩人中只剩下一個…"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"남은 사람은 이곳에서 있었던 모든 기억을 지우고 관리국을 떠나, 자유롭게 살아가기로.","JPN":"残された人はここでの記憶をすべて消して管理局を去り、自由に生きるのよ。","ENG":"The one left behind will erase every memory of this place and walk away from the Administration. To live free.","TWN":"剩下的人，要將這裡發生的一切記憶全部抹去，離開管理局，自由地生活。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"그럼… 다음에 다시 만나자.","JPN":"じゃあ……また会いましょう。","ENG":"So… until next time.","TWN":"那麼… 後會有期。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"그때까지 안녕.","JPN":"その時まで、さようなら。","ENG":"Goodbye.","TWN":"再見。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그래서…","JPN":"それで……","ENG":"So…","TWN":"所以…"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"누군가 그 메시지에 답장한 기록도 남아있나?","JPN":"誰かがそのメッセージに返信した記録もあるのか？","ENG":"Is there any record of someone replying to that message?","TWN":"有人回覆那則訊息的紀錄嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아니. 대신 송신에 실패한 기록은 있어.","JPN":"ううん。でも送信に失敗した記録はあるよ。","ENG":"No, just records of failed attempts to send one.","TWN":"沒有。但有發送失敗的紀錄。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그것도 아주 많이 시도했나 봐. 164번.","JPN":"しかも、たくさん試したみたい。164回。","ENG":"And a lot of attempts at that. 164 times.","TWN":"而且還試了很多次。164次。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이 두 사람. 누군진 몰라도 무사히 다시 만났으면 좋겠네.","JPN":"この2人、誰かは知らないけど……無事再会できるといいね。","ENG":"Whoever the two were, I hope they got to see each other again.","TWN":"這兩個人。雖然不知道是誰，但希望他們能平安再次相遇。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그런 좋은 결말을 기대하는 건 무리지. 이면세계에 처박힌 폐기 직전의 함선에서 발견한 메시지라면 더더욱 그렇고.","JPN":"そんな都合のいい結末、そうそうあるわけがない。裏世界に捨てられた、破棄直前の艦船から見つかったメッセージならなおさらだ。","ENG":"Wishful thinking. Especially when we found the message on a wrecked ship about to rot away in the Counterside.","TWN":"期待那樣美好的結局是不可能的。特別是在一艘即將報廢、被丟在異界的艦船上發現的訊息。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"으음…","JPN":"うーん……","ENG":"Hmm…","TWN":"嗯…"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"역시 떠나기 전에 조금만 더 확인해볼래!","JPN":"やっぱり、帰る前にもうちょっと調べてみる！","ENG":"I want to check a few more things before we leave!","TWN":"果然，離開前我還是想再確認一下！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L24_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"더 이상 머무는 건 이터니움 실드 낭비다.","JPN":"これ以上滞在するのはエタニウムシールドの無駄遣いだ。","ENG":"Staying down here any longer means wasting Eternium shield.","TWN":"再待下去只是浪費永恆之金護盾。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"어르신은 이 사람들 뒷얘기가 궁금하지도 않아? 분명 놓친 게 있을 거야.","JPN":"おばあさんはこの人たちがどうなったか気にならない？　きっと見逃した情報があるはずだよ。","ENG":"Don't you wanna know what happened to them? There's gotta be something we missed.","TWN":"阿姨你難道不好奇這兩個人後來的發展嗎？一定有什麼遺漏的。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"적당히 해, 꼬맹이. 이제 떠나야 한다고!","JPN":"いい加減にしろ、ガキ。そろそろ帰らなくてはならないんだ！","ENG":"That's enough, kid. We have to leave!","TWN":"夠了，小鬼。現在該走了！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L29_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아앗?! 갑자기 불이…?","JPN":"あっ！？　急に電気が……？","ENG":"Ah?! The lights, all of a sudden…","TWN":"啊？！突然沒電了…？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"조심해라. 누군가 전력을 내렸어.","JPN":"気をつけろ。誰かが電力を落とした。","ENG":"Be careful. Someone just killed the power.","TWN":"小心。有人切斷了電源。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"어르신이 방금 제어판에 손 올려서 망가진 거 아냐?","JPN":"おばあさんが今操作パネルに手を乗せたから壊れたんじゃない？","ENG":"Maybe it was you placing your hand on the control panel, breaking everything?","TWN":"是不是你剛才摸到控制面板，把它弄壞了？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"크흠, 차라리 잘 됐군. 빨리 일어서서…","JPN":"ゴホン、ちょうどよかった。早く立って……","ENG":"Ahem. Actually, this works out for the better. Let's get moving–","TWN":"咳，這樣也好。快點站起來…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"음?","JPN":"うん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"방금… 허공에서 뭔가 반짝거리지 않았어?","JPN":"今……宙で何か光らなかった？","ENG":"Did you see that…? Something shimmered in midair just now.","TWN":"剛才…空中是不是有什麼東西在閃爍？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"이건…?","JPN":"これは……？","ENG":"This is…?","TWN":"這是…？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"검은 이터니움… 이잖아?","JPN":"黒いエタニウム……？","ENG":"Dark Eternium…","TWN":"是黑色永恆之金…？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…방금 뭐였지?","JPN":"……今のは何だったんだ？","ENG":"…What just happened?","TWN":"…剛才那是什麼？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"1-0D…!","JPN":"1-0D…！","ENG":"1-0D…!","TWN":"1-0D…！"},"stage":{"bg":"PROLOGUE_01","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BATTLEFIELD"},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"피해…!","JPN":"避けろ……！","ENG":"Get down…!","TWN":"快躲開…！"},"stage":{"bg":"PROLOGUE_01","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SHILED_ADMIN_NULL_ADCOMMANDER","text":{"KOREA":"디재스터 다수 접근 중! 다음 포격이 오기 전에 산개해라!","JPN":"ディザスター多数接近中！　次の砲撃が来る前に散開しろ！","ENG":"Multiple Disasters incoming! Spread out before the next barrage hits!","TWN":"大量災厄接近中！在下次砲擊來臨前分散！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L49_1","type":"dialog","speaker":"SHILED_ADMIN_NULL_ADCOMMANDER","text":{"KOREA":"다소의 손실을 감수하더라도 침식 쐐기 제거를 최우선 목표로 한다!","JPN":"多少の犠牲を払ってでも、侵食楔の排除を最優先目標とする！","ENG":"Even if it costs us lives, our top priority is removing the Corrupted Wedge!","TWN":"就算承受一些損失，也要把移除侵蝕楔子作為首要目標！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWORD_NPC_ADMIN_14","text":{"KOREA":"1… 죽고 싶지 않아…","JPN":"1…死にたくないよ……","ENG":"1… I don't wanna die…","TWN":"1…我不想死…"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWORD_NPC_ADMIN_14","text":{"KOREA":"나 좀… 살려줘…","JPN":"頼む……助けてくれ……","ENG":"Please… save me…","TWN":"救救我…"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"난…","JPN":"私は……","ENG":"I…","TWN":"我…"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"나는… 너희를…","JPN":"私は……お前たちを……","ENG":"I… I–","TWN":"我…我會…"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SHILED_ADMIN_NULL_ADCOMMANDER","text":{"KOREA":"1-0D! 뭐하고 있나! 거기 남아있으면 포위되고 말 거다!","JPN":"1-0D！　何をしている！　そこにいると囲まれるぞ！","ENG":"1-0D! What are you doing?! You'll get surrounded!","TWN":"1-0D！你在做什麼！留在這裡會被包圍的！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L6_1","type":"dialog","speaker":"SHILED_ADMIN_NULL_ADCOMMANDER","text":{"KOREA":"이동해! 어서!","JPN":"移動しろ！　早く！","ENG":"Move! Now!","TWN":"快移動！快點！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"전부 다 보았음에도 결국 무엇 하나 바꾸지 못하는 거라면…","JPN":"全部見えているにも関わらず、結局何も変えられないなら……","ENG":"Even after seeing it all, if I still can't change a thing…","TWN":"就算全部都看到了，最終卻什麼都改變不了…"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"…이깟 쓸모없는 눈 따위는 차라리…","JPN":"……役に立たないこんな目なんか、いっそのこと……","ENG":"…Then these worthless eyes might as well–","TWN":"…那還不如把這雙沒用的眼睛…"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"어찌 된 영문인가.","JPN":"これはどうしたのだ。","ENG":"What happened here?","TWN":"怎麼回事。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"목숨은 부지했지만… 무리하게 침식체들과 전면전을 벌였어요.","JPN":"命は助かりましたが……無理して侵食体と正面から戦いました。","ENG":"She survived… but she charged into C.O.s head-on.","TWN":"雖然保住了一命…但卻與侵蝕體進行了魯莽的正面對決。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"동료 병사의 시신을 가져오고 싶었던 건지, 아니면 그냥 죽으려 했던 건진 모르겠지만요.","JPN":"同僚の遺体を持ち帰りたかったのか、ただ死にたいだけだったかは分かりません。","ENG":"Don't know if she was trying to bring her comrades' bodies back or just give up and die.","TWN":"我不知道她是想帶回同伴的屍體，還是只是想尋死。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"눈은 어쩌다 이지경이 된 거요?","JPN":"目はなぜこんなことに？","ENG":"What happened to her eyes?","TWN":"眼睛是怎麼回事？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"전투에서 유독 얼굴을 심하게 다쳤어요.","JPN":"戦闘での顔面の負傷が特にひどかったのです。","ENG":"Her face took the worst of the damage.","TWN":"她在戰鬥中臉部受了重傷。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"한쪽 눈은 간신히 수복했지만, 다른 하나는… 저희로서도 쉽지 않았죠.","JPN":"片方の目は辛うじて修復できましたが、片方は……私たちでも上手くいきませんでした。","ENG":"We barely managed to save one eye. The other… not so lucky.","TWN":"一隻眼睛勉強修復了，但另一隻…對我們來說也很棘手。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"박사, 내 한 가지 청이 있는데. 들어주겠나?","JPN":"博士、一つ頼みがあるんだが聞いてくれるか？","ENG":"Doctor, I've got a favor to ask. Will you hear me out?","TWN":"博士，我有一個請求。能答應我嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"박사의 연구에도 도움이 될 거라 생각하는데.","JPN":"博士の研究にも役に立つと思うんだが。","ENG":"I believe it'll benefit your research, too.","TWN":"我想這對博士的研究也有幫助。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"내가…","JPN":"私は……","ENG":"Why…","TWN":"我…"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_10"},{"id":"L32_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"왜 아직도 살아있지?","JPN":"なぜまだ生きている？","ENG":"Why am I still alive?","TWN":"為什麼還活著？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_11"},{"id":"L33_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"참으로 아이러니가 아니더냐.","JPN":"実に皮肉なことだ。","ENG":"Isn't it ironic?","TWN":"這真是諷刺。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_OPR_DOGABI_IN_CUTSCENE_26"},{"id":"L34_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"만물의 죽음을 보는 눈을 가졌으면서, 정작 자기 죽음은 내다보지 못하다니 말이다.","JPN":"万物の死を見る目を持っていても、自身の死を見れないとはな。","ENG":"You were born with eyes that see death. Yet can't see your own coming.","TWN":"明明擁有一雙能看見萬物死亡的眼睛，卻無法預見自己的死亡。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_OPR_DOGABI_IN_CUTSCENE_27"},{"id":"L36_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_12"},{"id":"L37_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"…나와 함께 하던 스쿼드가 전부 죽었어.","JPN":"……私と共に戦っていたスクワッドが全員死んだ。","ENG":"…My entire squad died.","TWN":"…和我一起的隊伍全部都死了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_13"},{"id":"L38_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"그래서 나도 죽을 생각으로 싸웠다. 이 두 눈마저 멀쩡할 줄은 몰랐지만 말이야.","JPN":"だから私も死ぬつもりで戦った。この両目もまともな状態で残っているとは思わなかった。","ENG":"So I fought like I had nothing to lose. Never thought I'd walk out with both eyes still fine.","TWN":"所以我也是抱著必死的決心戰鬥。沒想到這雙眼睛會毫髮無傷。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_14"},{"id":"L39_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"우리 눈은 처음부터 멀쩡한 적이 없었다.","JPN":"俺たちの目は最初からまともだったことなどない。","ENG":"Our eyes were never \\"fine\\" to begin with.","TWN":"我們的眼睛從來就沒有毫髮無傷過。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_OPR_DOGABI_IN_CUTSCENE_28"},{"id":"L40_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"죽음으로도 씻어내지 못할 지독한 저주가 붙어있지.","JPN":"死んでも解けない、忌々しい呪いがついている。","ENG":"They've been cursed from the start, too steeped in death to be washed clean.","TWN":"它附著著連死亡都無法洗清的惡毒詛咒。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_OPR_DOGABI_IN_CUTSCENE_29"},{"id":"L42_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"우리 눈이라고?","JPN":"「俺たちの目」？","ENG":"Our eyes?","TWN":"我們的眼睛？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_15"},{"id":"L43_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"그 안대… 당신도 눈 상태가 안 좋은 모양이군.","JPN":"その眼帯……お前も目の具合が悪いようだな。","ENG":"That eye patch… Looks like your eye isn't in great shape either.","TWN":"那個眼罩…你的眼睛狀況也不好嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_16"},{"id":"L44_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"이번 전투에 참여했다가 다치기라도 한 건가?","JPN":"今回の戦闘に参加して怪我をしたのか？","ENG":"Did you get hurt in this battle?","TWN":"是參加這次戰鬥受傷了嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_17"},{"id":"L45_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"내 눈이 왜 이런지 궁금하면, 네 오른쪽 눈을 한 번 감아보겠느냐?","JPN":"俺の目がどうしたのか気になるなら、お前の右目を閉じてみてくれるか？","ENG":"You want to know what happened to mine? Close your right eye for a second.","TWN":"如果你想知道我的眼睛為什麼會這樣，你試著閉上你的右眼如何？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_OPR_DOGABI_IN_CUTSCENE_30"},{"id":"L47_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"뭐?","JPN":"何？","ENG":"Huh?","TWN":"什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_18"},{"id":"L48_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"이렇게…?","JPN":"こうか……？","ENG":"Like this…?","TWN":"像這樣…？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_19"},{"id":"L49_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"허허, 그런 귀여운 표정도 지을 줄 아는구만.","JPN":"はは、そんな可愛い顔もできるんだな。","ENG":"Haha, so you do know how to make a cute face like that.","TWN":"哈哈，你也能露出這麼可愛的表情嗎。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_OPR_DOGABI_IN_CUTSCENE_31"},{"id":"L2_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"겨우 놀리려고 그런 거였나?","JPN":"からかうためだったのか？","ENG":"Are you messing with me?","TWN":"就為了捉弄我嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_20"},{"id":"L3_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"자, 이제 어떠냐? 그 눈에 뭐가 보이지?","JPN":"さ、どうだ？　その目に何が映る？","ENG":"So, what do you see now? Anything unusual?","TWN":"來，現在感覺如何？你的眼睛看到了什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02","voice":"AB_UI_UNIT_VOICE_NKM_OPR_DOGABI_IN_CUTSCENE_32"},{"id":"L5_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"가까이 오지 말라고! 쓸데없는 건 보고 싶지 않으니…","JPN":"近づくな！　余計なものは見たくな……","ENG":"Stay back! I don't want to see anything weir–","TWN":"不要靠近我！我不想看到沒用的東西…"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_21"},{"id":"L6_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"응…?","JPN":"ん……？","ENG":"Hmm…?","TWN":"嗯…？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_22"},{"id":"L7_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"왜 보이지 않지?","JPN":"なぜ見えない？","ENG":"Why can't I see anything?","TWN":"為什麼看不到？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_23"},{"id":"L8_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"네가 갖고 있던 눈은 네 혈맥이 품은 힘을 통달하지 못하여, 모든 죽음을 보되 그것을 외면하지 못했다.","JPN":"元々お前が持っていた目は、お前の血に宿る力に適応できず、すべての死を否応なしに見つめざるを得なかった。","ENG":"Your old eye was bound to your bloodline's power. It saw every death, but couldn't look away.","TWN":"你原本擁有的眼睛，無法駕馭你血脈所蘊含的力量，所以看見所有死亡，卻無法視而不見。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_OPR_DOGABI_IN_CUTSCENE_33"},{"id":"L9_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"하지만 그 눈은 다를 게야. 아주 오랜 세월 그 혈맥에 길들여져 온 눈이다.","JPN":"しかしその目は違う。非常に長い時間をかけてその血に適応した目だ。","ENG":"But this one is different. It's been molded by your bloodline over centuries.","TWN":"但那隻眼睛不同。那是經過漫長歲月，被那股血脈馴化過的眼睛。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_OPR_DOGABI_IN_CUTSCENE_34"},{"id":"L10_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"네가 원치 않는다면, 다른 사람의 죽음은 보이지 않게 되지.","JPN":"お前が望まないなら、他人の死は映らなくなる。","ENG":"If you don't want to see others' deaths, then you won't.","TWN":"如果你不願意，你就看不到別人的死亡。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_OPR_DOGABI_IN_CUTSCENE_35"},{"id":"L12_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"진짜로…?","JPN":"本当か……？","ENG":"Really…?","TWN":"真的嗎…？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_24"},{"id":"L13_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……."},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_25"},{"id":"L14_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"당신은 왜 그렇게 나에 대해 잘 알고 있는 거야?","JPN":"お前はなぜそこまで私に詳しい？","ENG":"Why do you know so much about me?","TWN":"你為什麼對我這麼了解？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_26"},{"id":"L15_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"율리아 박사조차 모르는 정보를 왜 당신은 알고 있지?!","JPN":"ユリア博士も知らない情報を、なぜお前が知っている？","ENG":"Even Dr. Yulia doesn't know that. How do you?","TWN":"連茱莉亞博士都不知道的情報，你為什麼會知道？！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_27"},{"id":"L16_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"난 그저 옛날 이야기에 나오는 늙은이일 뿐일세.","JPN":"俺は昔話に出てくる、ただの老いぼれだ。","ENG":"I'm just some old man from a forgotten tale.","TWN":"我只是個舊故事裡的老人而已。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_OPR_DOGABI_IN_CUTSCENE_36"},{"id":"L17_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그리고 자넨 앞으로의 시대를 써내려 갈 꼬맹이고 말이야.","JPN":"そしてお前はこれからの時代を紡いでいく若者だしな。","ENG":"And you're the kid who'll write the next one.","TWN":"而你，是個將要書寫未來時代的小丫頭。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_OPR_DOGABI_IN_CUTSCENE_37"},{"id":"L19_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"당신…","JPN":"お前……","ENG":"You…","TWN":"你…"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_28"},{"id":"L20_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"설마, 그 한쪽 눈…! 그렇게 된 이유가 나 때문인 거야?!","JPN":"まさか、その片目……！　そうなったのは、私のせいなのか！？","ENG":"Wait, your eye…! Are you saying it's like that because of me?!","TWN":"難道，那隻眼睛……！會變成那樣，是因為我嗎？！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그리 놀랄 거 없다.","JPN":"そう驚くことはない。","ENG":"No need to be so shocked.","TWN":"別這麼驚訝。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"처음부터 나누었어야 할 것을 지금에서야 네게 주었을 뿐이니.","JPN":"最初から渡すべきだったものを、今になってお前に渡したというだけだ。","ENG":"I just gave you what I should've given you long ago.","TWN":"我只是將從一開始就該給你的東西，現在還給你而已。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"처음부터 줬어야 했다고?","JPN":"最初から渡すべきだった？","ENG":"Should've given me long ago?","TWN":"從一開始就該給我？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"당신은… 나와 대체 어떤 사이인 거야?","JPN":"お前は……私とどういう関係なんだ？","ENG":"Who really are you…?","TWN":"你…和我到底是什麼關係？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"우리 두 사람은 삶, 죽음보다 더 두터운 인과로 얽혀 있다.","JPN":"俺たちは生と死よりも深い因果で結ばれている。","ENG":"You and I are tied by a causality thicker than life or death.","TWN":"我們兩人，有著比生與死更深的因果糾纏。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그 어떤 날카로운 것으로도 끊어내지 못할 인연이지.","JPN":"どんなに鋭い刃物でも断ち切れない因縁だ。","ENG":"A bond not even the sharpest blade could ever sever.","TWN":"那是任何利器都無法切斷的緣分。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"좀 더 쉽게 설명해주면 어디 덧나나?","JPN":"もう少し分かりやすい説明はできないのか？","ENG":"Mind explaining that so I can understand?","TWN":"說得簡單一點會怎麼樣？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"하하, 그야 물론이지.","JPN":"はは、できるさ。","ENG":"Haha, fair enough.","TWN":"哈哈，當然。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"내 이름은 명달이다.","JPN":"俺の名前はアカタツだ。","ENG":"My name is Myeongdal.","TWN":"我的名字是明達。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"이명달.","JPN":"ムラサメ・アカタツ。","ENG":"Lee Myeongdal.","TWN":"李明達。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"갑자기 이름은 왜…","JPN":"急に名前をなぜ……","ENG":"Why are you telling me your name, all of a sudden–","TWN":"突然說名字是…"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그리고 네 이름은 지수다.","JPN":"そしてお前の名前はシノだ。","ENG":"And yours is Jisoo.","TWN":"而你的名字是智秀。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"이지수.","JPN":"ムラサメ・シノ。","ENG":"Lee Jisoo.","TWN":"李智秀。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JISOO_NPC_CODE_14","text":{"KOREA":"이봐. 누구 멋대로 그런 걸…","JPN":"おい、何勝手にそんな……","ENG":"Hey. Who said you could–","TWN":"喂。誰讓你隨便…"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그 두 사람은 피로 이어진 혈연이다.","JPN":"2人は血の繋がった血縁だ。","ENG":"These two names are bound by blood.","TWN":"那兩個人是血緣相連的親人。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"무엇을 나누어도 아깝지 않을… <color=#ffd34c>가족</color>이다.","JPN":"何を渡しても惜しくない……<color=#ffd34c>家族</color>だ。","ENG":"So precious that I'd share even what I hold most dear… We are a <color=#ffd34c>family</color>.","TWN":"無論分享什麼，都不會感到可惜的…<color=#ffd34c>家人</color>。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…가족.","JPN":"……家族。","ENG":"…Family.","TWN":"…家人。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"어르신은… 과거에 대한 기억이 없다고 했었지?","JPN":"おばあさんは……過去の記憶がないって言ってたよね。","ENG":"Granny… Didn't you say you didn't remember your past?","TWN":"阿姨…你說過你沒有過去的記憶對吧？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"혹시 우리가 방금 본 게… 어르신의 과거인 걸까?","JPN":"もしかして今見たのって……おばあさんの過去なのかな？","ENG":"What we just saw… Do you think that was your past?","TWN":"我們剛才看到的…會不會就是你的過去？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};